def detect_failure_trigger(result: str, step: str) -> ReplanTrigger | None:
    """Fast rule-based failure detection — no LLM call needed.

    Catches obvious failures before the slower LLM check.
    """
    error_signals = [
        "error", "exception", "traceback", "failed",
        "not found", "permission denied", "timeout", "rate limit",
    ]
    result_lower = result.lower()
    for signal in error_signals:
        if signal in result_lower:
            return ReplanTrigger(
                type=TriggerType.STEP_FAILURE,
                step_index=0,
                detail=f"Error signal '{signal}' detected in result",
                severity=0.9,
            )
    return None

def detect_empty_result_trigger(result: str, step: str) -> ReplanTrigger | None:
    """Detect when a step that should produce output produced nothing."""
    if len(result.strip()) < 20:
        return ReplanTrigger(
            type=TriggerType.UNEXPECTED_RESULT,
            step_index=0,
            detail=f"Step '{step}' returned near-empty result (len={len(result.strip())})",
            severity=0.6,
        )
    return None

def detect_resource_trigger(
    tokens_used: int,
    token_budget: int,
    steps_remaining: int,
) -> ReplanTrigger | None:
    """Trigger re-planning when the token budget may not cover remaining steps."""
    avg_per_step = tokens_used / max(1, 5 - steps_remaining)  # rough estimate
    projected    = avg_per_step * steps_remaining
    remaining    = token_budget - tokens_used
    if projected > remaining * 0.9:
        return ReplanTrigger(
            type=TriggerType.RESOURCE_LIMIT,
            step_index=0,
            detail=f"Projected {projected:.0f} tokens needed, only {remaining} remaining",
            severity=0.8,
        )
    return None

from enum import IntEnum

class TriggerPriority(IntEnum):
    # Lower value = higher priority
    STEP_FAILURE = 1       # Execution is blocked — must resolve immediately
    RESOURCE_LIMIT = 2     # Running out of budget — pause before damage
    USER_INTERRUPTION = 3  # Explicit user override — always respected
    GOAL_DRIFT = 4         # Correctness concern — high but not blocking
    UNEXPECTED_RESULT = 5  # Surprising output — may need re-evaluation
    NEW_INFORMATION = 6    # Background update — re-plan when safe to do so

def select_highest_priority(triggers: list[ReplanTrigger]) -> ReplanTrigger | None:
    if not triggers:
        return None
    return min(triggers, key=lambda t: TriggerPriority[t.trigger_type.name])

def execute_with_priority(
    agent: anthropic.Anthropic,
    plan: list[Step],
    context: dict,
) -> list[dict]:
    results = []
    for step in plan:
        result = execute_step(step, context)
        triggers = check_triggers(agent, step, result, context)
        if triggers:
            primary = select_highest_priority(triggers)
            if primary.requires_immediate_replan:
                plan = replan(agent, plan, context, primary)
        results.append(result)
    return results
